groupButton1.label:
{{
  appsmith.store.cv_item_edit_index !== null &&
  appsmith.store.cv_item_edit_index !== undefined
    ? "ACTUALIZAR ÍTEM"
    : "AGREGAR ÍTEM"
}}

groupButton1.onClick:
{{
  (async () => {
    const items = appsmith.store.cv_items_proforma || [];
    const editIndex = appsmith.store.cv_item_edit_index;

    if (!appsmith.store.cv_item_producto?.producto_id) {
      showAlert("Selecciona un producto.", "warning");
      return;
    }

    if (!appsmith.store.cv_item_empaque?.empaque_id) {
      showAlert("Selecciona un empaque.", "warning");
      return;
    }

    if (Number(inpCvItemCantidad.text || 0) <= 0) {
      showAlert("Ingresa una cantidad válida.", "warning");
      return;
    }

    const itemBase = {
      item_no:
        editIndex !== null && editIndex !== undefined
          ? items[editIndex].item_no
          : items.length + 1,

      producto_id: appsmith.store.cv_item_producto?.producto_id,
      empaque_id: appsmith.store.cv_item_empaque?.empaque_id,

      codigo_producto: appsmith.store.cv_item_producto?.codigo_producto,
      subpartida: inpCvItemSubpartida.text,
      descripcion: inpCvItemDescripcion.text,
      marca: inpCvItemMarca.text,
      presentacion_comercial: inpCvItemPresentacion.text,
      tipo_empaque: appsmith.store.cv_item_empaque?.tipo_empaque,
      unidad_comercial: inpCvItemUnidadMedida.text,
      unidad_dian: inpCvItemUnidadDian.text,

      cantidad: Number(inpCvItemCantidad.text || 0),
      valor_unitario: Number(inpCvItemValorUnit.text || 0),
      total_valor: Number(inpCvItemTotalValor.text || 0),
      valor_flete: Number(inpCvItemValorFlete.text || 0),
      valor_seguro: Number(inpCvItemValorSeguro.text || 0),
      valor_gastos_destino: Number(inpCvItemValorGastDest.text || 0),
      subtotal: Number(inpCvItemSubtotal.text || 0),

      peso_neto_total: Number(inpCvItemPesoNetoTotal.text || 0),
      peso_bruto_total: Number(inpCvItemPesoBrutoTotal.text || 0),
      volumen_total: Number(inpCvItemVolumenTotal.text || 0)
    };

    let newItems;

    if (editIndex !== null && editIndex !== undefined) {
      newItems = items.map((x, i) => (i === editIndex ? itemBase : x));
      showAlert("Ítem actualizado.", "success");
    } else {
      newItems = [...items, itemBase];
      showAlert("Ítem agregado.", "success");
    }

    await storeValue("cv_items_proforma", newItems);
    await storeValue("cv_item_edit_index", null);
    await storeValue("cv_has_pending_changes", true);

    await JS_CvForm.clearItemForm();
  })()
}}

groupButton1awelw9rt4.onClick:
{{
(async () => {
  const row = tblCvDetalle.selectedRow;

  if (!row || !row.item_no) {
    showAlert("Selecciona un ítem para eliminar.", "warning");
    return;
  }

  await storeValue("delete_context", {
    action: "DELETE_CV_ITEM",
    item_no: row.item_no,
    id: row.id || null,
    label: row.descripcion || row.codigo_producto || ("Ítem " + row.item_no),
    message: "Vas a eliminar el ítem " + row.item_no + ". Esta acción requiere contraseña."
  });

  resetWidget("inpDeletePassword", true);
  resetWidget("taDeleteReason", true);
  showModal("mdlConfirmDelete");
})();
}}

groupButton2eurxo2u9t.onClick:
{{
  (() => {
    const selected = tblCvDetalle.selectedRow;
    const items = appsmith.store.cv_items_proforma || [];

    if (!selected) {
      showAlert("Selecciona un ítem para duplicar.", "warning");
      return;
    }

    const duplicated = {
      ...selected,
      item_no: items.length + 1
    };

    storeValue("cv_items_proforma", [...items, duplicated]);
    showAlert("Ítem duplicado.", "success");
  })()
}}

groupButton3.onClick:
{{
(async () => {
  const selected = tblCvDetalle.selectedRow;
  const items = appsmith.store.cv_items_proforma || [];

  if (!selected || !selected.item_no) {
    showAlert("Selecciona un ítem para editar.", "warning");
    return;
  }

  const index = items.findIndex(
    x => Number(x.item_no) === Number(selected.item_no)
  );

  if (index === -1) {
    showAlert("No se encontró el ítem en memoria.", "warning");
    return;
  }

  const item = items[index];

  await storeValue("cv_loading_item_edit", true);
  await storeValue("cv_item_edit_index", index);

  await storeValue("cv_item_producto", {
    producto_id: item.producto_id,
    codigo_producto: item.codigo_producto,
    descripcion: item.descripcion,
    marca: item.marca,
    partida_codigo: item.subpartida,
    partida_descripcion: item.partida_descripcion
  });

  await storeValue("cv_item_empaque", {
    empaque_id: item.empaque_id,
    presentacion_comercial: item.presentacion_comercial,
    tipo_empaque: item.tipo_empaque,
    unidad_comercial: item.unidad_comercial,
    unidad_dian: item.unidad_dian,
    peso_neto_unitario: item.cantidad ? Number(item.peso_neto_total || 0) / Number(item.cantidad || 1) : 0,
    peso_bruto_unitario: item.cantidad ? Number(item.peso_bruto_total || 0) / Number(item.cantidad || 1) : 0,
    volumen_unitario: item.cantidad ? Number(item.volumen_total || 0) / Number(item.cantidad || 1) : 0
  });

  await storeValue("cv_ui_item_tipo_producto", item.tipo_producto || "");
  await storeValue("cv_ui_item_categoria", item.categoria || "");
  await storeValue("cv_ui_item_producto", item.subcategoria || "");
  await storeValue("cv_ui_item_codigo", item.producto_id || "");
  await storeValue("cv_ui_item_empaque", item.empaque_id || "");

  await storeValue("cv_ui_item_cantidad", item.cantidad || "");
  await storeValue("cv_ui_item_valor_unit", item.valor_unitario || "");
  await storeValue("cv_ui_item_flete", item.valor_flete || "");
  await storeValue("cv_ui_item_seguro", item.valor_seguro || "");
  await storeValue("cv_ui_item_gastos_destino", item.valor_gastos_destino || "");

  await qCvItemCategoriaDropdown.run();
  await qCvItemProductoDropdown.run();
  await qCvItemCodigoDropdown.run();
  await qCvItemEmpaqueDropdown.run();

  resetWidget("slCvItemTipoProducto", true);
  resetWidget("slCvItemCategoria", true);
  resetWidget("slCvItemProducto", true);
  resetWidget("slCvItemCodigo", true);
  resetWidget("slCvItemEmpaque", true);

  resetWidget("inpCvItemCantidad", true);
  resetWidget("inpCvItemValorUnit", true);
  resetWidget("inpCvItemValorFlete", true);
  resetWidget("inpCvItemValorSeguro", true);
  resetWidget("inpCvItemValorGastDest", true);

  await storeValue("cv_loading_item_edit", false);

  showAlert("Ítem cargado para edición.", "success");
})();
}}

